-- =============================================================================
-- Migration 003: Quiz Questions Table + Corrected Module Titles
-- =============================================================================

-- ── Quiz questions (pre-generated by Spartan Lead Specialist Gem) ─────────────
CREATE TABLE IF NOT EXISTS public.quiz_questions (
  id            TEXT    PRIMARY KEY,
  module_id     TEXT    NOT NULL REFERENCES public.mjm_modules(id) ON DELETE CASCADE,
  sequence      INT     NOT NULL,
  question      TEXT    NOT NULL,
  option_a      TEXT    NOT NULL,
  option_b      TEXT    NOT NULL,
  option_c      TEXT    NOT NULL,
  option_d      TEXT    NOT NULL,
  correct       TEXT    NOT NULL CHECK (correct IN ('A','B','C','D')),
  explanation   TEXT,
  is_critical   BOOLEAN DEFAULT false,
  topic         TEXT,
  created_at    TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(module_id, sequence)
);

-- RLS: operators can read questions for modules visible to them (hard gate applies at mjm_modules)
ALTER TABLE public.quiz_questions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "quiz_questions_select" ON public.quiz_questions;
CREATE POLICY "quiz_questions_select" ON public.quiz_questions
  FOR SELECT USING (true);
-- Note: access is gated upstream — if RLS on mjm_modules blocks the module, the
-- operator never reaches this table. Admin upsert uses service role.

-- ── Quiz sessions (active exam tracking) ─────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.quiz_sessions (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  operator_id   UUID        NOT NULL REFERENCES public.operators(id) ON DELETE CASCADE,
  module_id     TEXT        NOT NULL REFERENCES public.mjm_modules(id),
  started_at    TIMESTAMPTZ DEFAULT NOW(),
  submitted_at  TIMESTAMPTZ,
  score         NUMERIC(5,2),
  passed        BOOLEAN,
  critical_fail BOOLEAN     DEFAULT false,
  answers       JSONB,      -- {"q-uuid": "A", ...}
  UNIQUE(operator_id, module_id, started_at)
);

ALTER TABLE public.quiz_sessions ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "quiz_sessions_select_own" ON public.quiz_sessions;
CREATE POLICY "quiz_sessions_select_own" ON public.quiz_sessions
  FOR SELECT USING (auth.uid() = operator_id);
-- Writes are service-role only.

-- ── Corrected module titles (actual MJM 2026 curriculum) ─────────────────────
UPDATE public.mjm_modules SET
  title = 'Legal Accreditation & GA 509-3-.01',
  description = 'Establishes the legal boundary of operator authority under GBPDSA. Covers the Georgia Board of Private Detectives and Security Agencies requirements, registration obligations, and the 16-hour annual firearms training mandate for MJM 2026 compliance.'
WHERE id = 'MOD-01';

UPDATE public.mjm_modules SET
  title = 'Justification & Deadly Force — OCGA 16-3-21',
  description = 'Defines the lawful conditions for use of deadly force under Georgia law. Deadly force is justified only to prevent death, great bodily injury, or a forcible felony. Property protection does not justify deadly force.',
  critical_question_ids = ARRAY['q-mod02-scenario1']
WHERE id = 'MOD-02';

UPDATE public.mjm_modules SET
  title = 'The Reasonable Man Doctrine',
  description = 'Prepares the operator for the courtroom audit. Examines Graham v. Connor and objective reasonableness — the law judges by information available at the moment, not 20/20 hindsight. Three-factor Graham standard: Severity, Threat, Resistance.',
  critical_question_ids = ARRAY['q-mod03-reasonableness']
WHERE id = 'MOD-03';

-- Clear any existing questions for these modules before seeding (idempotent re-run)
DELETE FROM public.quiz_questions WHERE module_id IN ('MOD-01', 'MOD-02', 'MOD-03');

