-- ── Seed questions for Module 02 ──────────────────────────────────────────────
INSERT INTO public.quiz_questions (id, module_id, sequence, question, option_a, option_b, option_c, option_d, correct, explanation, is_critical, topic)
VALUES
  ('q-mod02-scenario1', 'MOD-02', 1,
   'SCENARIO: A suspect has stolen a laptop from a secured facility and is fleeing on foot. The suspect is unarmed and poses no physical threat to any person. Do you deploy deadly force to stop them?',
